import { GoogleGenAI, Type } from "@google/genai";
import { WORLD_POPULATION } from "../constants";

if (!process.env.API_KEY) {
    throw new Error("API_KEY environment variable is not set.");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const responseSchema = {
    type: Type.OBJECT,
    properties: {
        estimated_count: {
            type: Type.NUMBER,
            description: "The estimated number of people worldwide to whom the statement applies."
        }
    },
    required: ["estimated_count"]
};

export const estimateBlessingCount = async (blessing: string): Promise<number> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Based on available global data, estimate how many people in the world the following statement applies to: "${blessing}"`,
            config: {
                systemInstruction: "You are a factual data analysis model. Your purpose is to provide a single numerical estimate based on the user's statement, assuming a world population of 8.1 billion. Do not add any commentary or explanation. Only return the JSON object as requested.",
                responseMimeType: "application/json",
                responseSchema: responseSchema,
            },
        });

        const jsonString = response.text.trim();
        const result = JSON.parse(jsonString);

        if (typeof result.estimated_count === 'number') {
            return result.estimated_count;
        } else {
            throw new Error('Invalid response format from AI. Expected a number.');
        }

    } catch (error) {
        console.error("Error calling Gemini API:", error);
        throw new Error("Could not get an estimate from the AI. The service might be temporarily unavailable.");
    }
};

export const estimateCombinedBlessingCount = async (blessings: string[]): Promise<number> => {
    if (blessings.length === 0) {
        return WORLD_POPULATION;
    }

    try {
        const prompt = `Based on available global data, estimate how many people in the world the following statements ALL apply to simultaneously: ${blessings.map(b => `"${b}"`).join('; ')}.`;

        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: {
                systemInstruction: "You are a factual data analysis model. Your purpose is to provide a single numerical estimate based on the user's statements, considering the intersection of all conditions. Assume a world population of 8.1 billion. Do not add any commentary or explanation. Only return the JSON object as requested.",
                responseMimeType: "application/json",
                responseSchema: responseSchema,
            },
        });

        const jsonString = response.text.trim();
        const result = JSON.parse(jsonString);

        if (typeof result.estimated_count === 'number') {
            return result.estimated_count;
        } else {
            throw new Error('Invalid response format from AI. Expected a number for combined count.');
        }

    } catch (error) {
        console.error("Error calling Gemini API for combined count:", error);
        throw new Error("Could not get a combined estimate from the AI. The service might be temporarily unavailable.");
    }
};


export const fetchPersonalizedInsight = async (blessings: string[]): Promise<string> => {
    if (blessings.length === 0) {
        return "";
    }
    try {
        const prompt = `Based on the following list of blessings, provide a single, encouraging, and personalized insight that summarizes the user's overall fortune. The blessings are: ${blessings.join(', ')}. Frame it as a "Personalized Insight". For example: "Having both education and access to clean water places you in a uniquely fortunate position globally." Keep it to one sentence.`;

        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: {
                 systemInstruction: "You are a positive and encouraging assistant. Your goal is to provide a single, insightful sentence based on the user's blessings.",
            },
        });

        return response.text;

    } catch (error) {
        console.error("Error fetching personalized insight from Gemini API:", error);
        throw new Error("Could not generate a personalized insight.");
    }
};

export const fetchInspirationalQuote = async (): Promise<string> => {
    try {
        const prompt = "Generate a short, single-sentence inspirational quote about gratitude or finding joy in small things.";
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: {
                 systemInstruction: "You are a source of positivity. Provide an uplifting and concise quote. Do not include quotation marks in the response.",
            },
        });
        return response.text.trim();
    } catch (error) {
        console.error("Error fetching inspirational quote:", error);
        return "Gratitude turns what we have into enough."; // Fallback quote
    }
};

import React from 'react';
import { Blessing } from '../types';
import { WORLD_POPULATION, CHART_COLORS } from '../constants';
import { CheckCircleIcon } from './icons';

interface BlessingListItemProps {
  blessing: Blessing;
  index: number;
}

const formatNumber = (num: number) => {
    if (num >= 1_000_000_000) {
        return `${(num / 1_000_000_000).toFixed(2)} billion`;
    }
    if (num >= 1_000_000) {
        return `${(num / 1_000_000).toFixed(2)} million`;
    }
    if (num >= 1_000) {
        return `${(num / 1_000).toFixed(1)}k`;
    }
    return num.toLocaleString();
};


const BlessingListItem: React.FC<BlessingListItemProps> = ({ blessing, index }) => {
    const percentage = ((blessing.count / WORLD_POPULATION) * 100).toFixed(2);
    const color = CHART_COLORS[index % CHART_COLORS.length];

    return (
        <div className="bg-green-50/50 dark:bg-green-900/20 border border-green-200 dark:border-green-800/50 p-4 rounded-lg flex items-center justify-between animate-fade-in-up">
            <div className="flex items-center gap-3">
                 <div className="w-3 h-3 rounded-full flex-shrink-0" style={{ backgroundColor: color }} aria-hidden="true"></div>
                <CheckCircleIcon className="w-6 h-6 text-green-500 dark:text-green-400 flex-shrink-0" />
                <p className="text-gray-700 dark:text-gray-300 flex-1">{blessing.text}</p>
            </div>
            <div className="text-right flex-shrink-0 ml-4">
                <p className="font-bold text-green-700 dark:text-green-400 text-lg">
                    Luckier than {formatNumber(blessing.count)}
                </p>
                <p className="text-sm text-gray-500 dark:text-gray-400">
                    That's {percentage}% of people
                </p>
            </div>
             <style>{`
                @keyframes fade-in-up {
                    0% {
                        opacity: 0;
                        transform: translateY(10px);
                    }
                    100% {
                        opacity: 1;
                        transform: translateY(0);
                    }
                }
                .animate-fade-in-up {
                    animation: fade-in-up 0.5s ease-out forwards;
                }
            `}</style>
        </div>
    );
};

export default BlessingListItem;

import React from 'react';
import { WORLD_POPULATION } from '../constants';
import { SparklesIcon } from './icons';

const formatNumber = (num: number) => {
    if (num >= 1_000_000_000) return `${(num / 1_000_000_000).toFixed(2)} billion`;
    if (num >= 1_000_000) return `${(num / 1_000_000).toFixed(2)} million`;
    if (num >= 1_000) return `${(num / 1_000).toFixed(1)}k`;
    return num.toLocaleString();
};

interface OverallSummaryProps {
  overallLuckierThan: number | null;
  isOverallLoading: boolean;
  insight: string | null;
  isInsightLoading: boolean;
}

const OverallSummary: React.FC<OverallSummaryProps> = ({ overallLuckierThan, isOverallLoading, insight, isInsightLoading }) => {
  const displayPercentage = overallLuckierThan !== null 
    ? Math.min((overallLuckierThan / WORLD_POPULATION) * 100, 100).toFixed(2)
    : '0.00';

  return (
    <div className="p-6 bg-blue-50/70 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800/50 rounded-lg space-y-4">
      <h2 className="text-xl font-bold text-gray-800 dark:text-gray-200 font-serif text-center">Your Blessing Summary</h2>

      <div className="text-center min-h-[100px] flex flex-col justify-center">
        {isOverallLoading ? (
             <div className="flex flex-col items-center justify-center animate-pulse">
                <p className="text-gray-500 dark:text-gray-400 mb-2">Calculating your overall fortune...</p>
                <div className="h-5 bg-gray-300 dark:bg-gray-600 rounded w-4/5 mb-2"></div>
                <div className="h-10 bg-gray-400 dark:bg-gray-500 rounded w-3/5 my-1"></div>
                <div className="h-5 bg-gray-300 dark:bg-gray-600 rounded w-4/5 mt-1"></div>
            </div>
        ) : (
            overallLuckierThan !== null && (
                <>
                    <p className="text-gray-600 dark:text-gray-400">In total, you are luckier than an estimated</p>
                    <p className="text-3xl md:text-4xl font-bold text-blue-600 dark:text-blue-400 my-1">{formatNumber(overallLuckierThan)} people</p>
                    <p className="text-md text-gray-600 dark:text-gray-400">That's more fortunate than <span className="font-bold">{displayPercentage}%</span> of the world's population.</p>
                </>
            )
        )}
      </div>

      {(insight || isInsightLoading) && (
        <div className="pt-4 mt-4 border-t border-blue-200 dark:border-blue-800/50">
            {isInsightLoading ? (
                <div className="animate-pulse flex items-center gap-3 justify-center">
                    <SparklesIcon className="w-5 h-5 text-yellow-400 dark:text-yellow-500 flex-shrink-0" />
                    <div className="h-4 bg-gray-300 dark:bg-gray-600 rounded w-3/4"></div>
                </div>
            ) : (
                insight && (
                    <div className="flex items-start gap-3 text-yellow-800 dark:text-yellow-200 bg-yellow-100/70 dark:bg-yellow-900/30 p-3 rounded-md">
                         <SparklesIcon className="w-6 h-6 text-yellow-500 flex-shrink-0 mt-0.5" />
                        <p className="text-sm italic">
                            <span className="font-semibold not-italic">Personalized Insight:</span> {insight}
                        </p>
                    </div>
                )
            )}
        </div>
      )}
    </div>
  );
};

export default OverallSummary;

import React from 'react';
import { Blessing } from '../types';
import BlessingInputForm from '../components/BlessingInputForm';
import PredefinedBlessings from '../components/PredefinedBlessings';
import BlessingList from '../components/BlessingList';
import OverallSummary from '../components/OverallSummary';
import BlessingsChart from '../components/BlessingsChart';
import SummaryActions from '../components/SummaryActions';
import { SparklesIcon } from '../components/icons';

interface CounterPageProps {
    blessings: Blessing[];
    isLoading: boolean;
    error: string | null;
    personalizedInsight: string | null;
    isInsightLoading: boolean;
    overallLuckierThan: number | null;
    isOverallLoading: boolean;
    onAddBlessing: (text: string, isPredefined: boolean) => void;
    onClear: () => void;
}

const CounterPage: React.FC<CounterPageProps> = ({
    blessings,
    isLoading,
    error,
    personalizedInsight,
    isInsightLoading,
    overallLuckierThan,
    isOverallLoading,
    onAddBlessing,
    onClear,
}) => {

    const formatNumber = (num: number) => {
        if (num >= 1_000_000_000) return `${(num / 1_000_000_000).toFixed(2)} billion`;
        if (num >= 1_000_000) return `${(num / 1_000_000).toFixed(2)} million`;
        return num.toLocaleString();
    };

    const overallSummaryText = `In total, I'm luckier than an estimated ${overallLuckierThan ? formatNumber(overallLuckierThan) : '...'} people.`;

    return (
        <>
            <header className="text-center mb-8">
                <div className="flex items-center justify-center gap-3">
                    <SparklesIcon className="w-10 h-10 text-yellow-500" />
                    <h1 className="text-4xl md:text-5xl font-bold text-gray-900 dark:text-gray-100 font-serif">Blessing Counter</h1>
                    <SparklesIcon className="w-10 h-10 text-yellow-500" />
                </div>
                <p className="mt-4 text-lg text-gray-600 dark:text-gray-400">Discover how fortunate you are. Add your blessings below.</p>
            </header>

            <div className="bg-white dark:bg-gray-800/50 rounded-xl shadow-lg p-6 md:p-8 space-y-6">
                <BlessingInputForm onAddBlessing={(text) => onAddBlessing(text, false)} isLoading={isLoading} />

                <PredefinedBlessings 
                    onAddBlessing={onAddBlessing} 
                    isLoading={isLoading} 
                    existingBlessings={blessings.map(b => b.text)} 
                />

                {error && (
                    <div className="bg-red-100 dark:bg-red-900/50 border-l-4 border-red-500 text-red-700 dark:text-red-300 p-4 rounded-md" role="alert">
                        <p className="font-bold">Error</p>
                        <p>{error}</p>
                    </div>
                )}

                <BlessingList blessings={blessings} isLoading={isLoading} />

                {blessings.length > 0 && (
                    <div className="pt-6 border-t border-gray-200 dark:border-gray-700 space-y-6">
                        <OverallSummary 
                            overallLuckierThan={overallLuckierThan}
                            isOverallLoading={isOverallLoading}
                            insight={personalizedInsight} 
                            isInsightLoading={isInsightLoading} 
                        />
                        <BlessingsChart blessings={blessings} />
                        <SummaryActions 
                            blessings={blessings} 
                            onClear={onClear}
                            overallSummaryText={overallSummaryText}
                            personalizedInsight={personalizedInsight}
                        />
                    </div>
                )}
            </div>
        </>
    );
};

export default CounterPage;

