import React, { useState } from 'react';
import { Blessing } from '../types';
import { ShareIcon, SaveIcon, ClipboardCheckIcon, TrashIcon, XIcon, FacebookIcon } from './icons';

interface SummaryActionsProps {
  blessings: Blessing[];
  onClear: () => void;
  overallSummaryText: string;
  personalizedInsight: string | null;
}

const SummaryActions: React.FC<SummaryActionsProps> = ({ blessings, onClear, overallSummaryText, personalizedInsight }) => {
  const [copied, setCopied] = useState<'' | 'share' | 'save'>('');

  const getFullShareText = () => {
    const header = "I counted my blessings today with the Blessing Counter! 🙏\n\n";
    const blessingsList = blessings.map((b, index) => `${index + 1}. ${b.text}`).join('\n');
    const footer = "\n\nTry it yourself to see how lucky you are!";
    return header + overallSummaryText + "\n\n" + (personalizedInsight ? `${personalizedInsight}\n\n` : '') + "My Blessings:\n" + blessingsList + footer;
  };

  const handleCopy = (type: 'share' | 'save') => {
    const textToCopy = getFullShareText();
    navigator.clipboard.writeText(textToCopy);
    setCopied(type);
    setTimeout(() => setCopied(''), 2000);
  };

  const shareToX = () => {
    const text = `I counted my blessings! ${overallSummaryText} ${personalizedInsight || ''} #Gratitude #BlessingCounter`;
    const url = `https://twitter.com/intent/tweet?text=${encodeURIComponent(text)}`;
    window.open(url, '_blank');
  };

  const shareToFacebook = () => {
    // Facebook doesn't allow custom text in the URL for standard shares without a public link, 
    // so we prompt users to copy and then open Facebook.
    const text = getFullShareText();
    navigator.clipboard.writeText(text);
    alert("Full summary copied to clipboard! Opening Facebook for you to paste and share.");
    window.open('https://www.facebook.com/sharer/sharer.php?u=' + encodeURIComponent(window.location.href), '_blank');
  };

  return (
    <div className="pt-6 border-t border-gray-200 dark:border-gray-700 flex flex-col space-y-4">
      <div className="flex flex-wrap items-center justify-between gap-4">
        <button
            onClick={onClear}
            className="inline-flex items-center justify-center px-4 py-2 font-medium text-sm text-red-600 dark:text-red-400 bg-red-100 dark:bg-red-900/40 rounded-lg hover:bg-red-200 dark:hover:bg-red-900/70 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500 transition-all"
        >
            <TrashIcon className="w-4 h-4 mr-2" />
            Clear All
        </button>

        <div className="flex flex-wrap items-center gap-3">
          <button
            onClick={() => handleCopy('share')}
            className="inline-flex items-center justify-center px-4 py-2 font-medium text-sm text-blue-600 dark:text-blue-300 bg-blue-100 dark:bg-blue-900/40 rounded-lg hover:bg-blue-200 dark:hover:bg-blue-900/70 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transition-all"
          >
            {copied === 'share' ? <ClipboardCheckIcon className="w-5 h-5 mr-2" /> : <ShareIcon className="w-5 h-5 mr-2" />}
            {copied === 'share' ? 'Copied!' : 'Copy Summary'}
          </button>
          <button
            onClick={() => handleCopy('save')}
            className="inline-flex items-center justify-center px-4 py-2 font-medium text-sm text-green-600 dark:text-green-300 bg-green-100 dark:bg-green-900/40 rounded-lg hover:bg-green-200 dark:hover:bg-green-900/70 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 transition-all"
          >
             {copied === 'save' ? <ClipboardCheckIcon className="w-5 h-5 mr-2" /> : <SaveIcon className="w-5 h-5 mr-2" />}
             {copied === 'save' ? 'Saved!' : 'Save Text'}
          </button>
        </div>
      </div>

      <div className="flex flex-wrap items-center justify-center gap-3 pt-2">
        <span className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider w-full text-center mb-1">Share your results</span>
        <button
          onClick={shareToX}
          className="inline-flex items-center justify-center px-4 py-2 font-medium text-sm text-white bg-black dark:bg-gray-700 rounded-lg hover:bg-gray-900 dark:hover:bg-gray-600 transition-all"
        >
          <XIcon className="w-4 h-4 mr-2" />
          Share on X
        </button>
        <button
          onClick={shareToFacebook}
          className="inline-flex items-center justify-center px-4 py-2 font-medium text-sm text-white bg-[#1877F2] rounded-lg hover:bg-[#0c63d4] transition-all"
        >
          <FacebookIcon className="w-4 h-4 mr-2" />
          Facebook
        </button>
      </div>
    </div>
  );
};

