import React from 'react';

export interface Blessing {
  id: number;
  text: string;
  count: number;
  perspectiveFact?: string; // New: A hard-hitting global fact to provide perspective
  isPredefined?: boolean;
}

export interface Achievement {
    id: string;
    name: string;
    description: string;
    check: (blessings: Blessing[]) => boolean;
