}

import { GoogleGenAI, Type } from "@google/genai";
import { WORLD_POPULATION } from "../constants";

if (!process.env.API_KEY) {
    throw new Error("API_KEY environment variable is not set.");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const blessingResponseSchema = {
    type: Type.OBJECT,
    properties: {
        estimated_count: {
            type: Type.NUMBER,
            description: "The estimated number of people worldwide to whom the statement applies."
        },
        perspective_fact: {
            type: Type.STRING,
            description: "A hard-hitting, factual global statistic."
        },
        village_stat: {
            type: Type.STRING,
            description: "A version of the stat for a village of 100 people. E.g., 'In a village of 100 people, only 5 would have this.'"
        }
    },
    required: ["estimated_count", "perspective_fact", "village_stat"]
};

export const estimateBlessingCount = async (blessing: string): Promise<{count: number, fact: string, villageStat: string}> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Estimate global data for: "${blessing}"`,
            config: {
                systemInstruction: "You are a data-driven sociologist. Provide a numerical estimate (8.1B population), an eye-opening fact, and a 'Global Village' stat (if the world were 100 people). Return JSON.",
                responseMimeType: "application/json",
                responseSchema: blessingResponseSchema,
            },
        });

        const result = JSON.parse(response.text.trim());
        return {
            count: result.estimated_count,
            fact: result.perspective_fact,
            villageStat: result.village_stat
        };
    } catch (error) {
        console.error("Error calling Gemini API:", error);
        throw new Error("Could not get an estimate.");
    }
};

export const generateBlessingImage = async (blessingText: string): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [
                    {
                        text: `A cinematic, peaceful, and high-quality artistic interpretation of the feeling of gratitude for: "${blessingText}". Style: Dreamy realism, soft lighting, 4k, trending on artstation.`,
                    },
                ],
            },
            config: {
                imageConfig: {
                    aspectRatio: "1:1"
                }
            }
        });

        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
        throw new Error("No image data returned");
    } catch (error) {
        console.error("Error generating image:", error);
        throw error;
    }
};

export const estimateCombinedBlessingCount = async (blessings: string[]): Promise<number> => {
    if (blessings.length === 0) return WORLD_POPULATION;
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Estimate how many people meet ALL these conditions: ${blessings.join('; ')}`,
            config: {
                systemInstruction: "Estimate the intersection. Population 8.1B. Return only JSON with 'estimated_count'.",
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: { estimated_count: { type: Type.NUMBER } },
                    required: ["estimated_count"]
                }
            },
        });
        return JSON.parse(response.text.trim()).estimated_count;
    } catch (error) {
        return WORLD_POPULATION / 10;
    }
};

export const fetchPersonalizedInsight = async (blessings: string[]): Promise<string> => {
    if (blessings.length === 0) return "";
    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Create a single encouraging sentence summarizing these blessings: ${blessings.join(', ')}`,
    });
    return response.text.trim();
};

export const fetchInspirationalQuote = async (): Promise<string> => {
    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: "Short quote about gratitude.",
    });
    return response.text.trim();
};

import React, { useState, useCallback, useEffect } from 'react';
import { Blessing, Achievement, JournalEntry } from './types';
import { WORLD_POPULATION, CHALLENGES, ACHIEVEMENTS } from './constants';
import { estimateBlessingCount, fetchPersonalizedInsight, estimateCombinedBlessingCount, fetchInspirationalQuote, generateBlessingImage } from './services/geminiService';

import Header from './components/Header';
import CounterPage from './pages/CounterPage';
import InspirationPage from './pages/InspirationPage';
import JournalPage from './pages/JournalPage';
import AchievementsPage from './pages/AchievementsPage';
import { SparklesIcon } from './components/icons';

type Page = 'counter' | 'inspiration' | 'journal' | 'achievements';
type Theme = 'light' | 'dark';

const App: React.FC = () => {
  const [blessings, setBlessings] = useState<Blessing[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [personalizedInsight, setPersonalizedInsight] = useState<string | null>(null);
  const [isInsightLoading, setIsInsightLoading] = useState<boolean>(false);

  const [overallLuckierThan, setOverallLuckierThan] = useState<number | null>(null);
  const [isOverallLoading, setIsOverallLoading] = useState<boolean>(false);

  const [unlockedAchievements, setUnlockedAchievements] = useState<Set<string>>(new Set());
  const [currentChallenge, setCurrentChallenge] = useState<string>('');
  const [inspirationalQuote, setInspirationalQuote] = useState<string>('');
  const [isQuoteLoading, setIsQuoteLoading] = useState<boolean>(false);
  const [journalEntries, setJournalEntries] = useState<JournalEntry[]>([]);

  const [page, setPage] = useState<Page>('counter');
  const [theme, setTheme] = useState<Theme>(() => {
    if (typeof window !== 'undefined' && window.localStorage) {
      const storedTheme = localStorage.getItem('theme') as Theme;
      if (storedTheme) return storedTheme;
      if (window.matchMedia('(prefers-color-scheme: dark)').matches) return 'dark';
    }
    return 'light';
  });

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  useEffect(() => {
    try {
        const storedEntries = localStorage.getItem('journalEntries');
        if (storedEntries) {
            setJournalEntries(JSON.parse(storedEntries));
        }
    } catch (e) {
        console.error("Failed to load journal entries", e);
    }
  }, []);

  const handleAddBlessing = useCallback(async (text: string, isPredefined: boolean = false) => {
    if (!text.trim()) return;

    if (blessings.some(b => b.text.toLowerCase() === text.toLowerCase())) {
        setError("You've already added this blessing.");
        setTimeout(() => setError(null), 3000);
        return;
    }

    setIsLoading(true);
    setError(null);

    try {
      const { count: blessedCount, fact, villageStat } = await estimateBlessingCount(text);
      const luckierThanCount = WORLD_POPULATION - blessedCount;

      const newBlessing: Blessing = {
        id: Date.now(),
        text,
        count: luckierThanCount > 0 ? luckierThanCount : 0,
        perspectiveFact: fact,
        villageStat,
        isPredefined,
      };

      setBlessings(prev => [...prev, newBlessing]);
    } catch (err) {
      console.error(err);
      setError(err instanceof Error ? err.message : 'An unknown error occurred.');
    } finally {
      setIsLoading(false);
    }
  }, [blessings]);

  const handleGenerateImage = async (id: number) => {
      const blessing = blessings.find(b => b.id === id);
      if (!blessing) return;

      try {
          const url = await generateBlessingImage(blessing.text);
          setBlessings(prev => prev.map(b => b.id === id ? { ...b, imageUrl: url } : b));
      } catch (e) {
          setError("Failed to generate image.");
      }
  };

  const handleNewInspiration = useCallback(async () => {
    setIsQuoteLoading(true);
    const newChallenge = CHALLENGES[Math.floor(Math.random() * CHALLENGES.length)];
    setCurrentChallenge(newChallenge);
    try {
        const newQuote = await fetchInspirationalQuote();
        setInspirationalQuote(newQuote);
    } catch (e) {
        setInspirationalQuote("Gratitude turns what we have into enough.");
    } finally {
        setIsQuoteLoading(false);
    }
  }, []);

  useEffect(() => {
    handleNewInspiration();
  }, [handleNewInspiration]);

  useEffect(() => {
    const newlyUnlocked = new Set<string>();
    ACHIEVEMENTS.forEach(ach => {
        if (!unlockedAchievements.has(ach.id) && ach.check(blessings)) {
            newlyUnlocked.add(ach.id);
        }
    });
    if (newlyUnlocked.size > 0) {
        setUnlockedAchievements(prev => new Set([...Array.from(prev), ...Array.from(newlyUnlocked)]));
    }
  }, [blessings]);

  useEffect(() => {
    if (blessings.length > 1) {
      const getInsight = async () => {
        setIsInsightLoading(true);
        try {
          const insight = await fetchPersonalizedInsight(blessings.map(b => b.text));
          setPersonalizedInsight(insight);
        } catch (e) {
          setPersonalizedInsight(null);
        } finally {
          setIsInsightLoading(false);
        }
      };
      getInsight();
    } else {
      setPersonalizedInsight(null);
    }
  }, [blessings]);

  useEffect(() => {
    const fetchOverallFortune = async () => {
      if (blessings.length > 1) {
        setIsOverallLoading(true);
        try {
          const combinedBlessedCount = await estimateCombinedBlessingCount(blessings.map(b => b.text));
          const luckierThanCount = WORLD_POPULATION - combinedBlessedCount;
          setOverallLuckierThan(luckierThanCount > 0 ? luckierThanCount : 0);
        } catch (e) {
          setOverallLuckierThan(null);
        } finally {
          setIsOverallLoading(false);
        }
      } else if (blessings.length === 1) {
        setOverallLuckierThan(blessings[0].count);
      } else {
        setOverallLuckierThan(null);
      }
    };
    fetchOverallFortune();
  }, [blessings]);

  const handleSaveJournalEntry = (content: string) => {
    const newEntry: JournalEntry = { id: Date.now(), date: new Date().toISOString(), content };
    const updatedEntries = [newEntry, ...journalEntries];
    setJournalEntries(updatedEntries);
    localStorage.setItem('journalEntries', JSON.stringify(updatedEntries));
  };

  const handleClear = () => {
    setBlessings([]);
    setError(null);
    setPersonalizedInsight(null);
    setOverallLuckierThan(null);
    setUnlockedAchievements(new Set());
  }

  const renderPage = () => {
    switch (page) {
        case 'inspiration':
            return <InspirationPage 
                        challenge={currentChallenge}
                        quote={inspirationalQuote}
                        isLoading={isQuoteLoading}
                        onNewInspiration={handleNewInspiration}
                    />;
        case 'journal':
            return <JournalPage entries={journalEntries} onSaveEntry={handleSaveJournalEntry} />;
        case 'achievements':
            return <AchievementsPage unlockedAchievementIds={unlockedAchievements} />;
        case 'counter':
        default:
            return <CounterPage
                        blessings={blessings}
                        isLoading={isLoading}
                        error={error}
                        personalizedInsight={personalizedInsight}
                        isInsightLoading={isInsightLoading}
                        overallLuckierThan={overallLuckierThan}
                        isOverallLoading={isOverallLoading}
                        onAddBlessing={handleAddBlessing}
                        onGenerateImage={handleGenerateImage}
                        onClear={handleClear}
                    />;
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-green-50 text-gray-800 dark:from-gray-900 dark:to-slate-800 dark:text-gray-200 antialiased selection:bg-blue-100 dark:selection:bg-blue-900">
      <Header 
        currentPage={page} 
        onNavigate={setPage} 
        unlockedAchievementsCount={unlockedAchievements.size}
        theme={theme}
        setTheme={setTheme}
      />
      <main className="container mx-auto px-4 py-8 md:py-12 max-w-4xl">
        {renderPage()}
        <footer className="text-center mt-12 mb-8 text-sm text-gray-400 dark:text-gray-500">
          <p className="flex items-center justify-center gap-2">
            Made with <SparklesIcon className="w-4 h-4 text-yellow-500" /> for the grateful heart.
          </p>
          <p className="mt-2">Estimates generated by AI based on global demographic trends.</p>
        </footer>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Blessing } from '../types';
import { WORLD_POPULATION, CHART_COLORS } from '../constants';
import { CheckCircleIcon, LightBulbIcon, SparklesIcon, LoaderIcon } from './icons';

interface BlessingListItemProps {
  blessing: Blessing;
  index: number;
  onGenerateImage?: (id: number) => void;
}

const formatNumber = (num: number) => {
    if (num >= 1_000_000_000) return `${(num / 1_000_000_000).toFixed(3)} billion`;
    if (num >= 1_000_000) return `${(num / 1_000_000).toFixed(2)} million`;
    if (num >= 1_000) return `${(num / 1_000).toFixed(1)}k`;
    return num.toLocaleString();
};


const BlessingListItem: React.FC<BlessingListItemProps> = ({ blessing, index, onGenerateImage }) => {
    const [showFact, setShowFact] = useState(false);
    const [isGenerating, setIsGenerating] = useState(false);
    const percentage = ((blessing.count / WORLD_POPULATION) * 100).toFixed(2);
    const color = CHART_COLORS[index % CHART_COLORS.length];

    const handleGenerate = async () => {
        if (!onGenerateImage) return;
        setIsGenerating(true);
        await onGenerateImage(blessing.id);
        setIsGenerating(false);
    };

    return (
        <div className="bg-white/60 dark:bg-gray-800/40 backdrop-blur-md border border-gray-200 dark:border-gray-700/50 p-5 rounded-2xl flex flex-col gap-4 shadow-sm hover:shadow-md transition-all animate-fade-in-up">
            <div className="flex items-start justify-between gap-3">
                <div className="flex items-start gap-3 flex-1">
                    <div className="w-2 h-10 rounded-full flex-shrink-0" style={{ backgroundColor: color }} aria-hidden="true"></div>
                    <div>
                        <p className="text-gray-800 dark:text-gray-200 font-semibold text-lg leading-tight">{blessing.text}</p>
                        {blessing.villageStat && (
                            <p className="text-xs font-bold text-blue-500 dark:text-blue-400 mt-1 uppercase tracking-wider">
                                🏠 {blessing.villageStat}
                            </p>
                        )}
                    </div>
                </div>
                <div className="text-right flex-shrink-0 ml-4">
                    <p className="font-black text-blue-600 dark:text-blue-400 text-xl leading-none">
                        {formatNumber(blessing.count)}
                    </p>
                    <p className="text-[10px] font-black text-gray-400 dark:text-gray-500 uppercase tracking-widest mt-1">
                        Luckier Than
                    </p>
                </div>
            </div>

            {blessing.imageUrl && (
                <div className="relative rounded-xl overflow-hidden aspect-video shadow-inner group">
                    <img src={blessing.imageUrl} alt={blessing.text} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-end p-4">
                        <p className="text-white text-xs font-medium italic">"{blessing.text}"</p>
                    </div>
                </div>
            )}

            <div className="flex items-center gap-3 mt-1">
                {blessing.perspectiveFact && (
                    <button 
                        onClick={() => setShowFact(!showFact)}
                        className="flex items-center gap-1.5 text-[10px] font-black text-yellow-600 dark:text-yellow-500 hover:text-yellow-700 dark:hover:text-yellow-400 transition-colors uppercase tracking-[0.15em] border border-yellow-200 dark:border-yellow-900/50 px-2 py-1 rounded-md"
                    >
                        <LightBulbIcon className="w-3 h-3" />
                        {showFact ? 'Hide Context' : 'Perspective'}
                    </button>
                )}

                {!blessing.imageUrl && onGenerateImage && (
                    <button 
                        onClick={handleGenerate}
                        disabled={isGenerating}
                        className="flex items-center gap-1.5 text-[10px] font-black text-purple-600 dark:text-purple-400 hover:text-purple-700 dark:hover:text-purple-300 transition-colors uppercase tracking-[0.15em] border border-purple-200 dark:border-purple-900/50 px-2 py-1 rounded-md disabled:opacity-50"
                    >
                        {isGenerating ? <LoaderIcon className="w-3 h-3 animate-spin" /> : <SparklesIcon className="w-3 h-3" />}
                        {isGenerating ? 'Painting...' : 'AI Postcard'}
                    </button>
                )}
            </div>

            {showFact && blessing.perspectiveFact && (
                <div className="p-3 bg-yellow-50/50 dark:bg-yellow-900/10 border border-yellow-100 dark:border-yellow-800/20 rounded-xl animate-slide-down">
                    <p className="text-xs text-yellow-800 dark:text-yellow-200 italic leading-relaxed">
                        {blessing.perspectiveFact}
                    </p>
                </div>
            )}

            <style>{`
                @keyframes slide-down {
                    from { opacity: 0; transform: translateY(-5px); }
                    to { opacity: 1; transform: translateY(0); }
                }
                .animate-slide-down { animation: slide-down 0.2s ease-out; }
            `}</style>
        </div>
    );
};

