import { GoogleGenAI, Type, Modality } from "@google/genai";
import { WORLD_POPULATION } from "../constants";

if (!process.env.API_KEY) {
    throw new Error("API_KEY environment variable is not set.");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const blessingResponseSchema = {
    type: Type.OBJECT,
    properties: {
        estimated_count: {
            type: Type.NUMBER,
            description: "The estimated number of people worldwide to whom the statement applies."
        },
        perspective_fact: {
            type: Type.STRING,
            description: "A hard-hitting, factual global statistic."
        },
        village_stat: {
            type: Type.STRING,
            description: "A version of the stat for a village of 100 people. E.g., 'In a village of 100 people, only 5 would have this.'"
        }
    },
    required: ["estimated_count", "perspective_fact", "village_stat"]
};

export const estimateBlessingCount = async (blessing: string): Promise<{count: number, fact: string, villageStat: string}> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Estimate global data for: "${blessing}"`,
            config: {
                systemInstruction: "You are a data-driven sociologist. Provide a numerical estimate (8.1B population), an eye-opening fact, and a 'Global Village' stat (if the world were 100 people). Return JSON.",
                responseMimeType: "application/json",
                responseSchema: blessingResponseSchema,
            },
        });

        const result = JSON.parse(response.text.trim());
        return {
            count: result.estimated_count,
            fact: result.perspective_fact,
            villageStat: result.village_stat
        };
    } catch (error) {
        console.error("Error calling Gemini API:", error);
        throw new Error("Could not get an estimate.");
    }
};

export const generateBlessingImage = async (blessingText: string): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [
                    {
                        text: `A cinematic, peaceful, and high-quality artistic interpretation of the feeling of gratitude for: "${blessingText}". Style: Dreamy realism, soft lighting, 4k, trending on artstation.`,
                    },
                ],
            },
            config: {
                imageConfig: {
                    aspectRatio: "1:1"
                }
            }
        });

        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
        throw new Error("No image data returned");
    } catch (error) {
        console.error("Error generating image:", error);
        throw error;
    }
};

export const generateSpeech = async (text: string): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text: `Read this calmly and peacefully: ${text}` }] }],
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: {
                        prebuiltVoiceConfig: { voiceName: 'Kore' },
                    },
                },
            },
        });

        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (!base64Audio) {
            throw new Error("Failed to generate audio data.");
        }
        return base64Audio;
    } catch (error) {
        console.error("Error generating speech:", error);
        throw error;
    }
};

export const estimateCombinedBlessingCount = async (blessings: string[]): Promise<number> => {
    if (blessings.length === 0) return WORLD_POPULATION;
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Estimate how many people meet ALL these conditions: ${blessings.join('; ')}`,
            config: {
                systemInstruction: "Estimate the intersection. Population 8.1B. Return only JSON with 'estimated_count'.",
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: { estimated_count: { type: Type.NUMBER } },
                    required: ["estimated_count"]
                }
            },
        });
        return JSON.parse(response.text.trim()).estimated_count;
    } catch (error) {
        return WORLD_POPULATION / 10;
    }
};

export const fetchPersonalizedInsight = async (blessings: string[]): Promise<string> => {
    if (blessings.length === 0) return "";
    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Create a single encouraging sentence summarizing these blessings: ${blessings.join(', ')}`,
    });
    return response.text.trim();
};

export const fetchInspirationalQuote = async (): Promise<string> => {
    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: "Short quote about gratitude.",
    });
    return response.text.trim();
};

import React, { useState, useRef } from 'react';
import { WORLD_POPULATION } from '../constants';
import { SparklesIcon, SpeakerWaveIcon, StopIcon, LoaderIcon } from './icons';
import { generateSpeech } from '../services/geminiService';

const formatNumber = (num: number) => {
    if (num >= 1_000_000_000) return `${(num / 1_000_000_000).toFixed(3)} billion`;
    if (num >= 1_000_000) return `${(num / 1_000_000).toFixed(2)} million`;
    if (num >= 1_000) return `${(num / 1_000).toFixed(1)}k`;
    return num.toLocaleString();
};

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface OverallSummaryProps {
  overallLuckierThan: number | null;
  isOverallLoading: boolean;
  insight: string | null;
  isInsightLoading: boolean;
}

const OverallSummary: React.FC<OverallSummaryProps> = ({ overallLuckierThan, isOverallLoading, insight, isInsightLoading }) => {
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isTtsLoading, setIsTtsLoading] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);

  const displayPercentage = overallLuckierThan !== null 
    ? Math.min((overallLuckierThan / WORLD_POPULATION) * 100, 100).toFixed(2)
    : '0.00';

  const stopSpeaking = () => {
    if (sourceNodeRef.current) {
        sourceNodeRef.current.stop();
        sourceNodeRef.current = null;
    }
    setIsSpeaking(false);
  };

  const handleListen = async () => {
    if (isSpeaking) {
        stopSpeaking();
        return;
    }

    if (!insight) return;

    setIsTtsLoading(true);
    try {
        const base64Audio = await generateSpeech(insight);

        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }

        const audioBuffer = await decodeAudioData(
            decode(base64Audio),
            audioContextRef.current,
            24000,
            1
        );

        const source = audioContextRef.current.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioContextRef.current.destination);
        source.onended = () => {
            setIsSpeaking(false);
            sourceNodeRef.current = null;
        };

        sourceNodeRef.current = source;
        setIsSpeaking(true);
        source.start();

    } catch (error) {
        console.error("TTS Error:", error);
    } finally {
        setIsTtsLoading(false);
    }
  };

  return (
    <div className="p-6 bg-blue-50/70 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800/50 rounded-lg space-y-4">
      <h2 className="text-xl font-bold text-gray-800 dark:text-gray-200 font-serif text-center">Your Blessing Summary</h2>

      <div className="text-center min-h-[100px] flex flex-col justify-center">
        {isOverallLoading ? (
             <div className="flex flex-col items-center justify-center animate-pulse">
                <p className="text-gray-500 dark:text-gray-400 mb-2">Calculating your overall fortune...</p>
                <div className="h-5 bg-gray-300 dark:bg-gray-600 rounded w-4/5 mb-2"></div>
                <div className="h-10 bg-gray-400 dark:bg-gray-500 rounded w-3/5 my-1"></div>
                <div className="h-5 bg-gray-300 dark:bg-gray-600 rounded w-4/5 mt-1"></div>
            </div>
        ) : (
            overallLuckierThan !== null && (
                <>
                    <p className="text-gray-600 dark:text-gray-400">In total, you are luckier than an estimated</p>
                    <p className="text-3xl md:text-4xl font-bold text-blue-600 dark:text-blue-400 my-1">{formatNumber(overallLuckierThan)} people</p>
                    <p className="text-md text-gray-600 dark:text-gray-400">That's more fortunate than <span className="font-bold">{displayPercentage}%</span> of the world's population.</p>
                </>
            )
        )}
      </div>

      {(insight || isInsightLoading) && (
        <div className="pt-4 mt-4 border-t border-blue-200 dark:border-blue-800/50">
            {isInsightLoading ? (
                <div className="animate-pulse flex items-center gap-3 justify-center">
                    <SparklesIcon className="w-5 h-5 text-yellow-400 dark:text-yellow-500 flex-shrink-0" />
                    <div className="h-4 bg-gray-300 dark:bg-gray-600 rounded w-3/4"></div>
                </div>
            ) : (
                insight && (
                    <div className="flex flex-col gap-3 text-yellow-800 dark:text-yellow-200 bg-yellow-100/70 dark:bg-yellow-900/30 p-4 rounded-xl relative group">
                         <div className="flex items-start gap-3">
                            <SparklesIcon className="w-6 h-6 text-yellow-500 flex-shrink-0 mt-0.5" />
                            <p className="text-sm italic leading-relaxed pr-8">
                                <span className="font-semibold not-italic">Personalized Insight:</span> {insight}
                            </p>
                            <button
                                onClick={handleListen}
                                disabled={isTtsLoading}
                                title="Voice of Peace"
                                className={`absolute top-4 right-4 p-2 rounded-full transition-all ${
                                    isSpeaking 
                                    ? 'bg-red-500 text-white animate-pulse' 
                                    : 'bg-yellow-500/20 text-yellow-700 dark:text-yellow-400 hover:bg-yellow-500 hover:text-white'
                                }`}
                            >
                                {isTtsLoading ? (
                                    <LoaderIcon className="w-4 h-4 animate-spin" />
                                ) : isSpeaking ? (
                                    <StopIcon className="w-4 h-4" />
                                ) : (
                                    <SpeakerWaveIcon className="w-4 h-4" />
                                )}
                            </button>
                         </div>
                    </div>
                )
            )}
        </div>
      )}
    </div>
  );
};

export default OverallSummary;

