import React, { useState } from 'react';
import { Blessing } from '../types';
import { ShareIcon, SaveIcon, ClipboardCheckIcon, TrashIcon, XIcon, FacebookIcon, LinkedInIcon } from './icons';

interface SummaryActionsProps {
  blessings: Blessing[];
  onClear: () => void;
  overallSummaryText: string;
  personalizedInsight: string | null;
}

const SummaryActions: React.FC<SummaryActionsProps> = ({ blessings, onClear, overallSummaryText, personalizedInsight }) => {
  const [copied, setCopied] = useState<'' | 'share' | 'save'>('');

  const getFullShareText = () => {
    const header = "Gratitude is a superpower. 🌍✨\n\nI just realized I'm more fortunate than billions of people.\n\n";
    const footer = "\n\nShift your perspective here: [Link]";
    return header + overallSummaryText + "\n\n" + (personalizedInsight ? `💡 Insight: ${personalizedInsight}\n\n` : '') + footer;
  };

  const handleCopy = (type: 'share' | 'save') => {
    const textToCopy = getFullShareText();
    navigator.clipboard.writeText(textToCopy);
    setCopied(type);
    setTimeout(() => setCopied(''), 2000);
  };

  const shareToX = () => {
    const countText = overallSummaryText.replace("In total, I'm luckier than an estimated ", "").replace(" people.", "");
    const text = `Mind blown. 🤯 I'm luckier than ${countText} people on Earth. \n\nGratitude isn't just a feeling, it's a statistic. \n\nCheck your luck: #BlessingCounter #Gratitude`;
    const url = `https://twitter.com/intent/tweet?text=${encodeURIComponent(text)}`;
    window.open(url, '_blank');
  };

  const shareToFacebook = () => {
    const text = getFullShareText();
    navigator.clipboard.writeText(text);
    alert("Full summary copied! Opening Facebook...");
    window.open('https://www.facebook.com/sharer/sharer.php?u=' + encodeURIComponent(window.location.href), '_blank');
  };

  const shareToLinkedIn = () => {
    const text = getFullShareText();
    navigator.clipboard.writeText(text);
    alert("Full summary copied! Opening LinkedIn...");
    // LinkedIn doesn't support pre-filling text via URL parameters easily for standard shares.
    // We provide the URL and the user can paste the summary we just copied to their clipboard.
    const url = `https://www.linkedin.com/sharing/share-offsite/?url=${encodeURIComponent(window.location.href)}`;
    window.open(url, '_blank');
  };

  return (
    <div className="pt-6 border-t border-gray-200 dark:border-gray-700 flex flex-col space-y-6">
      <div className="flex flex-wrap items-center justify-between gap-4">
        <button
            onClick={onClear}
            className="inline-flex items-center justify-center px-4 py-2 font-medium text-xs text-gray-500 dark:text-gray-400 bg-gray-100 dark:bg-gray-800 rounded-lg hover:bg-red-100 hover:text-red-600 transition-all uppercase tracking-widest"
        >
            <TrashIcon className="w-4 h-4 mr-2" />
            Reset
        </button>

        <div className="flex flex-wrap items-center gap-3">
          <button
            onClick={() => handleCopy('share')}
            className="inline-flex items-center justify-center px-5 py-2.5 font-bold text-sm text-blue-600 dark:text-blue-300 bg-blue-100 dark:bg-blue-900/40 rounded-xl hover:bg-blue-200 transition-all shadow-sm"
          >
            {copied === 'share' ? <ClipboardCheckIcon className="w-5 h-5 mr-2" /> : <ShareIcon className="w-5 h-5 mr-2" />}
            {copied === 'share' ? 'Copied' : 'Copy Summary'}
          </button>
        </div>
      </div>

      <div className="bg-gray-50 dark:bg-gray-900/40 p-4 rounded-2xl flex flex-col items-center justify-center gap-4">
        <span className="text-[10px] font-black text-gray-400 dark:text-gray-500 uppercase tracking-[0.2em]">Broadcast your Fortune</span>
        <div className="flex gap-4">
            <button
            onClick={shareToX}
            className="group flex items-center justify-center w-12 h-12 text-white bg-black dark:bg-gray-700 rounded-full hover:scale-110 transition-transform shadow-lg"
            title="Share on X"
            >
            <XIcon className="w-5 h-5" />
            </button>
            <button
            onClick={shareToFacebook}
            className="group flex items-center justify-center w-12 h-12 text-white bg-[#1877F2] rounded-full hover:scale-110 transition-transform shadow-lg"
            title="Share on Facebook"
            >
            <FacebookIcon className="w-5 h-5" />
            </button>
            <button
            onClick={shareToLinkedIn}
            className="group flex items-center justify-center w-12 h-12 text-white bg-[#0A66C2] rounded-full hover:scale-110 transition-transform shadow-lg"
            title="Share on LinkedIn"
            >
            <LinkedInIcon className="w-5 h-5" />
            </button>
        </div>
      </div>
    </div>
  );
};

export default SummaryActions;

import React, { useState } from 'react';
import { Blessing } from '../types';
import { ShareIcon, SaveIcon, ClipboardCheckIcon, TrashIcon, XIcon, FacebookIcon, LinkedInIcon } from './icons';

interface SummaryActionsProps {
  blessings: Blessing[];
  onClear: () => void;
  overallSummaryText: string;
  personalizedInsight: string | null;
}

const SummaryActions: React.FC<SummaryActionsProps> = ({ blessings, onClear, overallSummaryText, personalizedInsight }) => {
  const [copied, setCopied] = useState<'' | 'share' | 'save'>('');

  const getFullShareText = () => {
    const header = "Gratitude is a superpower. 🌍✨\n\nI just used the Blessing Counter and realized my life is statistically extraordinary.\n\n";
    const footer = "\n\nGain your own perspective here: [Your App URL]";
    const insightPart = personalizedInsight ? `💡 My Reflection: ${personalizedInsight}\n` : '';

    return `${header}${overallSummaryText}\n\n${insightPart}${footer}`;
  };

  const handleCopy = (type: 'share' | 'save') => {
    const textToCopy = getFullShareText();
    navigator.clipboard.writeText(textToCopy);
    setCopied(type);
    setTimeout(() => setCopied(''), 2000);
  };

  const shareToX = () => {
    const countText = overallSummaryText.replace("In total, I'm luckier than an estimated ", "").replace(" people.", "");
    const text = `Mind blown. 🤯 I'm luckier than ${countText} people on Earth. \n\nGratitude isn't just a feeling, it's a statistic. \n\nCheck your luck: #BlessingCounter #Gratitude`;
    const url = `https://twitter.com/intent/tweet?text=${encodeURIComponent(text)}`;
    window.open(url, '_blank');
  };

  const shareToFacebook = () => {
    const text = getFullShareText();
    navigator.clipboard.writeText(text);
    alert("Perspective Summary copied to clipboard! Paste it into your post.");
    window.open('https://www.facebook.com/sharer/sharer.php?u=' + encodeURIComponent(window.location.href), '_blank');
  };

  const shareToLinkedIn = () => {
    const text = getFullShareText();
    navigator.clipboard.writeText(text);
    // Visual feedback is better than a native alert for world-class apps
    setCopied('share');
    setTimeout(() => {
        setCopied('');
        window.open(`https://www.linkedin.com/sharing/share-offsite/?url=${encodeURIComponent(window.location.href)}`, '_blank');
    }, 800);
  };

  return (
    <div className="pt-6 border-t border-gray-200 dark:border-gray-700 flex flex-col space-y-6">
      <div className="flex flex-wrap items-center justify-between gap-4">
        <button
            onClick={onClear}
            className="inline-flex items-center justify-center px-4 py-2 font-medium text-xs text-gray-500 dark:text-gray-400 bg-gray-100 dark:bg-gray-800 rounded-lg hover:bg-red-100 hover:text-red-600 transition-all uppercase tracking-widest"
        >
            <TrashIcon className="w-4 h-4 mr-2" />
            Reset Sanctuary
        </button>

        <div className="flex flex-wrap items-center gap-3">
          <button
            onClick={() => handleCopy('share')}
            className="inline-flex items-center justify-center px-5 py-2.5 font-bold text-sm text-blue-600 dark:text-blue-300 bg-blue-100 dark:bg-blue-900/40 rounded-xl hover:bg-blue-200 transition-all shadow-sm active:scale-95"
          >
            {copied === 'share' ? <ClipboardCheckIcon className="w-5 h-5 mr-2" /> : <ShareIcon className="w-5 h-5 mr-2" />}
            {copied === 'share' ? 'Copied to Clipboard' : 'Copy Full Summary'}
          </button>
        </div>
      </div>

      <div className="bg-gradient-to-r from-gray-50 to-white dark:from-gray-900/40 dark:to-gray-800/20 p-6 rounded-3xl border border-gray-100 dark:border-gray-700/30 flex flex-col items-center justify-center gap-6 shadow-inner">
        <span className="text-[10px] font-black text-gray-400 dark:text-gray-500 uppercase tracking-[0.3em]">Broadcast your perspective</span>
        <div className="flex gap-6">
            <button
                onClick={shareToX}
                className="group flex items-center justify-center w-14 h-14 text-white bg-black dark:bg-gray-700 rounded-2xl hover:scale-110 hover:-rotate-6 transition-all shadow-xl"
                title="Share on X"
            >
                <XIcon className="w-6 h-6" />
            </button>
            <button
                onClick={shareToFacebook}
                className="group flex items-center justify-center w-14 h-14 text-white bg-[#1877F2] rounded-2xl hover:scale-110 hover:rotate-6 transition-all shadow-xl"
                title="Share on Facebook"
            >
                <FacebookIcon className="w-6 h-6" />
            </button>
            <button
                onClick={shareToLinkedIn}
                className="group flex items-center justify-center w-14 h-14 text-white bg-[#0A66C2] rounded-2xl hover:scale-110 hover:-rotate-6 transition-all shadow-xl"
                title="Share on LinkedIn"
            >
                <LinkedInIcon className="w-6 h-6" />
            </button>
        </div>
        <p className="text-[10px] text-gray-400 italic">Clicking LinkedIn/Facebook will copy the summary to your clipboard first.</p>
      </div>
    </div>
  );
};

export default SummaryActions;

import React from 'react';
import { Achievement } from '../types';

interface BadgeProps {
    achievement: Achievement;
    isUnlocked: boolean;
}

const Badge: React.FC<BadgeProps> = ({ achievement, isUnlocked }) => {
    const Icon = achievement.icon;

    return (
        <div
            className={`flex flex-col items-center text-center p-5 rounded-2xl border-2 transition-all duration-500 transform ${
                isUnlocked
                ? 'bg-gradient-to-b from-yellow-50 to-white border-yellow-200 dark:from-yellow-900/20 dark:to-gray-800 dark:border-yellow-700/50 shadow-lg scale-100 opacity-100'
                : 'bg-gray-50/50 border-gray-100 dark:bg-gray-800/40 dark:border-gray-700/30 scale-95 opacity-60 grayscale'
            }`}
            title={isUnlocked ? `Unlocked: ${achievement.description}`: achievement.description}
        >
            <div
                className={`w-20 h-20 rounded-full flex items-center justify-center transition-all duration-700 shadow-inner ${
                    isUnlocked
                    ? 'bg-yellow-400 animate-badge-pop'
                    : 'bg-gray-200 dark:bg-gray-700'
                }`}
            >
                <Icon className={`w-10 h-10 ${isUnlocked ? 'text-white' : 'text-gray-400 dark:text-gray-500'}`} />
            </div>
            <p className={`mt-4 font-black text-xs uppercase tracking-widest ${isUnlocked ? 'text-yellow-800 dark:text-yellow-400' : 'text-gray-400 dark:text-gray-600'}`}>
                {achievement.name}
            </p>
            <p className={`text-[10px] leading-tight mt-1 px-2 ${isUnlocked ? 'text-gray-600 dark:text-gray-400' : 'text-gray-400 dark:text-gray-600 italic'}`}>
                {isUnlocked ? achievement.description : 'Requirement hidden'}
            </p>

            <style>{`
                @keyframes badge-pop {
                    0% { transform: scale(0.8); }
                    50% { transform: scale(1.1); }
                    100% { transform: scale(1); }
                }
                .animate-badge-pop {
                    animation: badge-pop 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275);
                }
            `}</style>
        </div>
    );
};

export default Badge;
